                .attr('x', (row) => xScale(row[config.x.field]) ?? 0)
                .attr('y', (row) => (row[config.y.field] >= 0 ? yScale(row[config.y.field]) : yScale(0)))
                .attr('width', xScale.bandwidth())
                .attr('height', (row) => Math.abs(yScale(row[config.y.field]) - yScale(0)))
                .attr('fill', config.markStyle.fill);

              // ANNOTATION_LAYER_START
              const meanValue = 5.068;
              const aboveAverage = rows.filter(row => row[config.y.field] > meanValue);
              aboveAverage.forEach((row, index) => {
                annotationLayer.append('text')
                  .attr('x', xScale(row[config.x.field]) + xScale.bandwidth() / 2)
                  .attr('y', yScale(row[config.y.field]) - 10)
                  .attr('fill', 'blue')
                  .attr('text-anchor', 'middle')
                  .text(row[config.x.field]);
              });
              // ANNOTATION_LAYER_END

              return {
                svg: svg.node(),
                chartLayer: chartLayer.node(),
                annotationLayer: annotationLayer.node(),
                xScale,
                yScale,
                colorScale,
                data,
              };
            }
